$filter_zone   = $_GET['zone']   ?? '';
$filter_sort   = $_GET['sort']   ?? 'latest';
$search        = trim($_GET['q'] ?? '');
$page          = max(1, (int)($_GET['page'] ?? 1));
$per_page      = 12;
$offset        = ($page - 1) * $per_page;

// ── Build query ──────────────────────────────────────────
$where  = ["c.status != 'closed'"];
$params = [];
$types  = '';

if ($filter_cat)    { $where[] = 'c.category = ?';  $params[] = $filter_cat;    $types .= 's'; }
if ($filter_status) { $where[] = 'c.status = ?';    $params[] = $filter_status; $types .= 's'; }
if ($filter_zone)   { $where[] = 'c.zone = ?';      $params[] = $filter_zone;   $types .= 's'; }
if ($search)        { $where[] = '(c.title LIKE ? OR c.location LIKE ?)';
                      $params[] = "%$search%"; $params[] = "%$search%"; $types .= 'ss'; }

$w_sql = implode(' AND ', $where);

$order = match($filter_sort) {
    'oldest'   => 'c.created_at ASC',
    'resolved' => 'c.resolved_at DESC',
    default    => 'c.created_at DESC',
};

// ── Always-available lookup arrays ──────────────────────
$cat_icon  = ['road'=>'🚧','water'=>'💧','electricity'=>'⚡','sanitation'=>'🧹','property'=>'🏛️','lost'=>'🔍'];
$cat_label = ['road'=>'Road & Infra','water'=>'Water','electricity'=>'Electricity','sanitation'=>'Sanitation','property'=>'Public Property','lost'=>'Lost & Found'];
$s_cfg     = [
    'new'        => ['label'=>'New',         'cls'=>'s-new'],
    'assigned'   => ['label'=>'Assigned',    'cls'=>'s-assigned'],
    'in_progress'=> ['label'=>'In Progress', 'cls'=>'s-prog'],
    'resolved'   => ['label'=>'Resolved',    'cls'=>'s-resolved'],
    'escalated'  => ['label'=>'Escalated',   'cls'=>'s-esc'],
    'closed'     => ['label'=>'Closed',      'cls'=>'s-closed'],
];

// ── REAL DB QUERY ────────────────────────────────────────
$db_complaints = [];
if (isset($conn) && $conn) {
    $real_where  = ["c.status != 'closed'"];
    $real_params = [];
    $real_types  = '';
    if ($filter_cat)    { $real_where[] = 'c.category = ?';  $real_params[] = $filter_cat;    $real_types .= 's'; }
    if ($filter_status) { $real_where[] = 'c.status = ?';    $real_params[] = $filter_status; $real_types .= 's'; }
    if ($filter_zone)   { $real_where[] = 'c.zone = ?';      $real_params[] = $filter_zone;   $real_types .= 's'; }
    if ($search)        { $real_where[] = '(c.title LIKE ? OR c.location LIKE ?)';
                          $real_params[] = "%$search%"; $real_params[] = "%$search%"; $real_types .= 'ss'; }
    $real_w_sql = implode(' AND ', $real_where);
    $real_order = match($filter_sort) {
        'oldest'   => 'c.created_at ASC',
        'resolved' => 'c.resolved_at DESC',
        default    => 'c.created_at DESC',
    };
    $data_sql = "SELECT c.*, u.name as citizen_name, o.name as officer_name
                 FROM complaints c
                 LEFT JOIN users u  ON c.citizen_id  = u.id
                 LEFT JOIN users o  ON c.officer_id  = o.id
                 WHERE $real_w_sql
                 ORDER BY $real_order";
    if ($real_params) {
        $stmt_data = $conn->prepare($data_sql);
        $stmt_data->bind_param($real_types, ...$real_params);
        $stmt_data->execute();
        $res = $stmt_data->get_result();
    } else {
        $res = $conn->query($data_sql);
    }
    if ($res) { while ($row = $res->fetch_assoc()) { $db_complaints[] = $row; } }
}

