  ['id'=>12,'complaint_no'=>'GRV-0012','category'=>'lost','title'=>'Found stray cat with kittens near Old Goa church — needs shelter','description'=>'A mother cat with 4 kittens is living under the steps near the Basilica of Bom Jesus. They need food and shelter. Can municipal help arrange care?','location'=>'Basilica of Bom Jesus, Old Goa','zone'=>'Panaji','status'=>'new','priority'=>'low','citizen_name'=>'Agnes Monteiro','officer_name'=>null,'photo_url'=>'data:image/jpeg;base64,','created_at'=>date('Y-m-d H:i:s',strtotime('-1 day')),'resolved_at'=>null,'latitude'=>15.5009,'longitude'=>73.9115],
];

// Apply filters to dummy data
$filtered = array_filter($all_complaints, function($c) use ($filter_cat,$filter_status,$filter_zone,$search) {
    if ($filter_cat    && $c['category'] !== $filter_cat)    return false;
    if ($filter_status && $c['status']   !== $filter_status) return false;
    if ($filter_zone   && $c['zone']     !== $filter_zone)   return false;
    if ($search && stripos($c['title'].$c['location'], $search) === false) return false;
    return true;
});

// Sort dummy data
usort($filtered, function($a,$b) use ($filter_sort) {
    if ($filter_sort === 'oldest')  return strtotime($a['created_at']) - strtotime($b['created_at']);
    if ($filter_sort === 'resolved') return strtotime($b['resolved_at']??'0') - strtotime($a['resolved_at']??'0');
    return strtotime($b['created_at']) - strtotime($a['created_at']);
});

// ── MERGE real DB + dummy complaints ────────────────────
// Real DB complaints come first (newest), then dummy data
$merged = array_merge($db_complaints, array_values($filtered));

// Remove duplicates by complaint_no (real DB wins)
$seen = [];
$unique_merged = [];
foreach ($merged as $c) {
    $key = $c['complaint_no'] ?? $c['id'];
    if (!isset($seen[$key])) {
        $seen[$key] = true;
        $unique_merged[] = $c;
    }
}

// Sort merged list
usort($unique_merged, function($a,$b) use ($filter_sort) {
    if ($filter_sort === 'oldest')  return strtotime($a['created_at']) - strtotime($b['created_at']);
    if ($filter_sort === 'resolved') return strtotime($b['resolved_at']??'0') - strtotime($a['resolved_at']??'0');
    return strtotime($b['created_at']) - strtotime($a['created_at']);
});

$total_rows  = count($unique_merged);
$total_pages = max(1, ceil($total_rows / $per_page));
$complaints  = array_slice($unique_merged, $offset, $per_page);

// ── Summary stats (merged) ───────────────────────────────
$summary = [
    'total'     => $total_rows,
    'new_c'     => count(array_filter($unique_merged, fn($c)=>$c['status']==='new')),
    'prog'      => count(array_filter($unique_merged, fn($c)=>$c['status']==='in_progress')),
    'resolved'  => count(array_filter($unique_merged, fn($c)=>$c['status']==='resolved')),
    'escalated' => count(array_filter($unique_merged, fn($c)=>$c['status']==='escalated')),
];

// ── Zones (merged) ──────────────────────────────────────
$zones = array_unique(array_filter(array_column($unique_merged, 'zone'), fn($z) => !empty(trim((string)$z))));
sort($zones);

$is_logged_in = !empty($_SESSION['user_id']);
$role         = $_SESSION['role'] ?? '';
$dash_link    = match($role) {
    'citizen'   => 'citizen_dashboard.php',
    'officer'   => 'officer_dashboard.php',
    'regulator' => 'regulator_dashboard.php',
    default     => 'citizen_login.php',
};

function time_ago($datetime) {
    $diff = time() - strtotime($datetime);
    if ($diff < 60)    return 'just now';
    if ($diff < 3600)  return floor($diff/60).'m ago';
    if ($diff < 86400) return floor($diff/3600).'h ago';
    if ($diff < 604800) return floor($diff/86400).'d ago';
    return date('d M Y', strtotime($datetime));
}
