.search-ico{position:absolute;left:10px;top:50%;transform:translateY(-50%);font-size:.82rem;color:var(--muted)}

/* ── RIGHT CONTENT ── */
.right-col{min-width:0}

/* TOOLBAR */
.toolbar{
  display:flex;align-items:center;justify-content:space-between;
  margin-bottom:14px;gap:12px;
}
.tbl-count{font-size:.78rem;color:var(--muted)}
.tbl-count strong{color:var(--text);font-weight:700}
.tbl-sort{display:flex;align-items:center;gap:8px}
.sort-label{font-size:.72rem;color:var(--muted)}
.sort-sel{
  padding:6px 10px;background:var(--white);
  border:1px solid var(--border);border-radius:7px;
  font-family:'Plus Jakarta Sans',sans-serif;font-size:.75rem;
  color:var(--text);outline:none;cursor:pointer;
  transition:border-color .14s;
}
.sort-sel:focus{border-color:var(--a2)}

/* VIEW TOGGLE */
.view-toggle{display:flex;gap:3px;background:var(--bg2);padding:3px;border-radius:7px}
.vt-btn{
  width:28px;height:28px;border-radius:5px;
  display:flex;align-items:center;justify-content:center;
  background:none;border:none;cursor:pointer;
  color:var(--muted);font-size:.8rem;transition:all .14s;
}
.vt-btn.on{background:var(--white);color:var(--text);box-shadow:var(--shadow)}

/* ── COMPLAINT CARDS (grid view) ── */
.comp-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px}
.comp-card{
  background:rgba(255,255,255,.9);
  border:1px solid var(--border);
  border-radius:12px;
  overflow:hidden;
  box-shadow:var(--shadow);
  transition:all .2s;cursor:pointer;
  display:flex;flex-direction:column;
}
.comp-card:hover{transform:translateY(-3px);box-shadow:0 8px 24px rgba(79,156,249,.15);border-color:var(--border2)}
.cc-photo{
  width:100%;height:140px;
  background:var(--bg2);
  overflow:hidden;position:relative;
  flex-shrink:0;
}
.cc-photo img{width:100%;height:100%;object-fit:cover}
.cc-photo-placeholder{
  width:100%;height:100%;
  display:flex;align-items:center;justify-content:center;
  flex-direction:column;gap:6px;
}
.cc-ph-ico{font-size:2rem;opacity:.3}
.cc-ph-txt{font-size:.65rem;color:var(--muted);opacity:.6}
.cc-cat-badge{
  position:absolute;top:10px;left:10px;
  background:rgba(13,31,45,.7);
  backdrop-filter:blur(6px);
  padding:3px 10px;border-radius:20px;
  font-size:.6rem;font-weight:600;color:#f0f4ff;
}
.cc-body{padding:14px;flex:1;display:flex;flex-direction:column}
.cc-id{font-size:.58rem;font-weight:600;color:var(--a);font-family:monospace;letter-spacing:.3px;margin-bottom:4px}
.cc-title{font-size:.82rem;font-weight:700;color:var(--text);margin-bottom:6px;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}
.cc-loc{font-size:.68rem;color:var(--muted);margin-bottom:10px;display:flex;align-items:center;gap:4px}
.cc-foot{display:flex;align-items:center;justify-content:space-between;margin-top:auto}
.cc-time{font-size:.62rem;color:var(--muted)}

/* CARD ACTION BUTTONS */
.cc-actions{display:flex;gap:7px;margin-top:10px;padding-top:10px;border-top:1px solid var(--border)}
.cc-btn{
  flex:1;padding:7px 10px;border-radius:7px;
  font-size:.68rem;font-weight:600;text-align:center;
  background:var(--bg2);border:1px solid var(--border);
  color:var(--muted2);transition:all .14s;
}
.cc-btn:hover{background:var(--bg);border-color:var(--border2);color:var(--text)}
.cc-btn-track{background:var(--ag);border-color:rgba(16,158,136,.2);color:var(--a)}
.cc-btn-track:hover{background:var(--a3);border-color:var(--a2);color:var(--a)}

/* ── LIST VIEW ── */
.comp-list-view{display:flex;flex-direction:column;gap:0;border:1px solid var(--border);border-radius:12px;overflow:hidden;background:rgba(255,255,255,.9);box-shadow:var(--shadow)}
.cl-row{
  display:flex;align-items:center;gap:14px;
  padding:12px 18px;
  border-bottom:1px solid var(--border);
}
.cl-row:last-child{border-bottom:none}
.cl-thumb{
  width:52px;height:52px;border-radius:8px;
  overflow:hidden;flex-shrink:0;
  background:var(--bg2);
  display:flex;align-items:center;justify-content:center;
}
.cl-thumb img{width:100%;height:100%;object-fit:cover}
.cl-thumb-ph{font-size:1.4rem}
.cl-body{flex:1;min-width:0;cursor:pointer}
.cl-body:hover .cl-title{color:var(--a)}
.cl-top{display:flex;align-items:center;gap:8px;margin-bottom:3px}
.cl-id{font-size:.58rem;font-weight:600;color:var(--a);font-family:monospace;letter-spacing:.3px}
.cl-cat{font-size:.6rem;color:var(--muted);background:var(--bg2);padding:1px 7px;border-radius:4px}
.cl-title{font-size:.8rem;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-bottom:2px;transition:color .14s}
.cl-meta{display:flex;align-items:center;gap:6px}
.cl-loc{font-size:.65rem;color:var(--muted)}
.cl-time{font-size:.62rem;color:var(--muted)}
.cl-right{display:flex;align-items:center;gap:8px;flex-shrink:0}
.cl-photo{font-size:.7rem;color:var(--muted)}
.cl-track-btn{
  padding:5px 11px;border-radius:6px;
  font-size:.67rem;font-weight:600;
  background:var(--ag);border:1px solid rgba(16,158,136,.2);
  color:var(--a);transition:all .14s;white-space:nowrap;
}
.cl-track-btn:hover{background:var(--a3);border-color:var(--a2)}

/* STATUS PILLS */
.pill{display:inline-flex;align-items:center;padding:2px 8px;border-radius:4px;font-size:.6rem;font-weight:700;letter-spacing:.3px;white-space:nowrap}
.s-new{background:rgba(16,158,136,.1);color:var(--a)}
.s-assigned{background:var(--amber-bg);color:var(--amber)}
.s-prog{background:var(--blue-bg);color:var(--blue)}
.s-resolved{background:var(--green-bg);color:var(--green)}
.s-closed{background:var(--bg2);color:var(--muted)}
.s-esc{background:var(--red-bg);color:var(--red)}

/* EMPTY */
.empty{text-align:center;padding:60px 20px;background:var(--card);border:1px solid var(--border);border-radius:12px}
.empty-ico{font-size:2.5rem;margin-bottom:10px;opacity:.4}
.empty-title{font-size:.9rem;font-weight:700;color:var(--text);margin-bottom:5px}
.empty-sub{font-size:.75rem;color:var(--muted);margin-bottom:18px}

/* PAGINATION */
.pagination{display:flex;align-items:center;justify-content:center;gap:4px;margin-top:22px}
.pg-btn{
  width:34px;height:34px;border-radius:7px;
  display:flex;align-items:center;justify-content:center;
  font-size:.78rem;font-weight:600;
  background:var(--white);border:1px solid var(--border);
  color:var(--muted2);cursor:pointer;transition:all .14s;
  text-decoration:none;
}
.pg-btn:hover{background:var(--a3);border-color:var(--a2);color:var(--a)}
.pg-btn.on{background:var(--a);border-color:var(--a);color:#f0f4ff}
.pg-btn.disabled{opacity:.4;pointer-events:none}
.pg-dots{font-size:.78rem;color:var(--muted);padding:0 4px}

/* RESPONSIVE */
@media(max-width:900px){
  .main-wrap{grid-template-columns:1fr}
  .filters{position:static}
  .comp-grid{grid-template-columns:1fr 1fr}
  .stat-bar{grid-template-columns:1fr 1fr}
}
@media(max-width:600px){
  .comp-grid{grid-template-columns:1fr}
  .main-wrap{padding:14px 16px}
  .stat-bar{grid-template-columns:1fr 1fr}
}

