<script>
// View toggle
function setView(v){
  document.getElementById('view-grid').style.display = v==='grid' ? 'grid'  : 'none';
  document.getElementById('view-list').style.display = v==='list' ? 'flex'  : 'none';
  document.getElementById('btn-grid').classList.toggle('on', v==='grid');
  document.getElementById('btn-list').classList.toggle('on', v==='list');
  localStorage.setItem('pb_view', v);
}
// Restore saved view
(function(){ const v=localStorage.getItem('pb_view'); if(v==='list') setView('list'); })();
</script>
</body>
</html>
