// ── Helper: build URL preserving current filters ────────
function buildUrl($overrides=[]) {
    $params = array_merge([
        'cat'    => $_GET['cat']    ?? '',
        'status' => $_GET['status'] ?? '',
        'zone'   => $_GET['zone']   ?? '',
        'sort'   => $_GET['sort']   ?? 'latest',
        'q'      => $_GET['q']      ?? '',
        'page'   => $_GET['page']   ?? 1,
    ], $overrides);
    $params = array_filter($params, fn($v) => $v !== '' && $v !== 'latest' && $v !== 1);
    return 'public_board.php' . ($params ? '?' . http_build_query($params) : '');
}
